window.renderAlertTape = function(items){
  const body = document.getElementById('alertTapeBody');
  const count = document.getElementById('alertTapeCount');
  if (!body || !count) return;
  const rows = Array.isArray(items) ? items : [];
  count.textContent = String(rows.length);
  if (!rows.length){
    body.innerHTML = '<div class="muted">No alerts yet.</div>';
    return;
  }
  body.innerHTML = rows.slice(0, 20).map(a => {
    const reasons = Array.isArray(a.reasons) ? a.reasons.slice(0,4).join(' • ') : '';
    const flags = Array.isArray(a.flags) ? a.flags.slice(0,4).join(' • ') : '';
    const stateTxt = `${esc2(a.from_state || '—')} → ${esc2(a.to_state || '—')}`;
    const bucket = String(a.alert_bucket || a.event_type || '').toLowerCase();
    const severity = bucket === 'triggered' ? 'badge-green' : (bucket === 'ready' ? 'badge-amber' : (bucket === 'near_trigger' ? 'badge-blue' : 'badge-gray'));
    const bucketLabel = bucket ? bucket.replaceAll('_', ' ') : 'transition';
    return `<div style="padding:10px 12px; border:1px solid var(--border); border-radius:12px; background:rgba(255,255,255,0.03);">
      <div style="display:flex; justify-content:space-between; gap:12px; flex-wrap:wrap; align-items:center;">
        <div><b>${esc2(a.symbol || '—')}</b> <span class="tag">${esc2(a.playbook || '—')}</span> <span class="badge ${severity}">${esc2(bucketLabel)}</span> <span class="miniMuted">${stateTxt}</span></div>
        <div class="muted">${a.event_ts ? new Date(Number(a.event_ts)*1000).toLocaleTimeString() : ''}</div>
      </div>
      <div class="muted" style="margin-top:4px;">price $${fmt2(a.price,2)} • spread ${fmt2(a.spread_pct,2)}% • chase-R ${fmt2(a.live_chase_r,2)} • catalyst ${fmt2(a.catalyst_score,2)} • context ${fmt2(a.context_score,2)}</div>
      <div class="muted" style="margin-top:4px;">why: ${esc2(reasons || 'state transition')}${flags ? ` • flags: ${esc2(flags)}` : ''}</div>
    </div>`;
  }).join('');
};

