from __future__ import annotations

import json
import os
from typing import Any

class OptionalRedisPublisher:
    def __init__(self) -> None:
        self.enabled = str(os.getenv("ORB_REDIS_ENABLED", "0")).strip().lower() in {"1","true","yes","on"}
        self.channel_prefix = str(os.getenv("ORB_REDIS_CHANNEL_PREFIX", "orb")).strip() or "orb"
        self._client = None
        self._error = None
        if self.enabled:
            try:
                import redis  # type: ignore
                self._client = redis.Redis(
                    host=os.getenv("ORB_REDIS_HOST", "127.0.0.1"),
                    port=int(os.getenv("ORB_REDIS_PORT", "6379")),
                    db=int(os.getenv("ORB_REDIS_DB", "0")),
                    password=os.getenv("ORB_REDIS_PASSWORD") or None,
                    socket_timeout=2.0,
                    socket_connect_timeout=2.0,
                    decode_responses=True,
                )
                self._client.ping()
            except Exception as e:
                self._error = f"redis_init_failed: {type(e).__name__}: {e}"
                self._client = None

    @property
    def error(self) -> str | None:
        return self._error

    def publish(self, topic: str, payload: dict[str, Any]) -> None:
        if not self.enabled:
            return
        if self._client is None:
            raise RuntimeError(self._error or "redis_not_initialized")
        channel = f"{self.channel_prefix}:{str(topic).strip()}"
        self._client.publish(channel, json.dumps(payload or {}, separators=(",", ":"), default=str))

