function _showBanner(alert) {
  const banner = document.getElementById('sniperBanner');
  if (!banner) return;
  document.getElementById('sniperBannerSymbol').textContent = alert.symbol;
  const dirEl = document.getElementById('sniperBannerDir');
  dirEl.textContent = alert.direction;
  dirEl.style.background = alert.direction === 'LONG' ? 'rgba(74,222,128,0.18)' : 'rgba(248,113,113,0.18)';
  dirEl.style.color       = alert.direction === 'LONG' ? '#4ade80' : '#f87171';

  // Grade pill (populated by background KTT fetch)
  const gradeEl = document.getElementById('sniperBannerGrade');
  const wlEl    = document.getElementById('sniperBannerWL');
  if (gradeEl) {
    if (alert.ktt_grade && alert.ktt_grade !== '?') {
      const gc = {A:'#4ade80',B:'#fbbf24',C:'#f97316',D:'#f87171'}[alert.ktt_grade] || '#94a3b8';
      gradeEl.textContent = `${alert.ktt_grade} ${alert.ktt_score}`;
      gradeEl.style.color = gc; gradeEl.style.borderColor = gc; gradeEl.style.display = 'inline';
    } else if (alert.ktt_grade === '?') {
      gradeEl.textContent = '\u2014';
      gradeEl.style.color = '#475569'; gradeEl.style.display = 'inline';
    } else {
      gradeEl.textContent = 'grading\u2026';
      gradeEl.style.color = '#475569'; gradeEl.style.display = 'inline';
    }
  }
  if (wlEl) wlEl.style.display = (alert.direction === 'LONG' || alert.direction === 'SHORT') ? 'inline' : 'none';

  document.getElementById('sniperBannerTags').textContent = (alert.tags || []).slice(0,3).join(' · ');
  document.getElementById('sniperBannerHeadline').textContent = alert.headline;
  const price = alert.price ? `$${Number(alert.price).toFixed(2)} at fire` : '';
  const conf  = alert.confidence ? `conf ${Math.round(alert.confidence)}` : '';
  document.getElementById('sniperBannerMeta').textContent = [price, conf, alert.source].filter(Boolean).join(' · ');
  document.getElementById('sniperBannerAge').textContent = _secAgo(alert.fired_at) || '';
  banner.style.display = 'block';
  clearTimeout(_bannerTimer);
  _bannerTimer = setTimeout(() => { banner.style.display = 'none'; }, 90000);
}

let _currentBannerTs = null;

function _updateBannerGrade(alert) {
  const gradeEl = document.getElementById('sniperBannerGrade');
  if (!gradeEl) return;
  if (alert.ktt_grade && alert.ktt_grade !== '?') {
    const gc = {A:'#4ade80',B:'#fbbf24',C:'#f97316',D:'#f87171'}[alert.ktt_grade] || '#94a3b8';
    gradeEl.textContent = `${alert.ktt_grade} ${alert.ktt_score}`;
    gradeEl.style.color = gc; gradeEl.style.display = 'inline';
  } else if (alert.ktt_grade === '?') {
    gradeEl.textContent = '\u2014';
    gradeEl.style.color = '#475569'; gradeEl.style.display = 'inline';
  }
}

function _processSniperAlerts(alerts) {
  const fresh = alerts.filter(a => !_sniperSeen.has(String(a.fired_ts)));
  if (!fresh.length) {
    // Re-render band in case ktt_grade was added by background thread
    _renderSniperBand(alerts);
    // Update floating banner grade if it's still showing and grade just arrived
    if (_currentBannerTs != null) {

