def _grade_for_confidence(score: float) -> str:
    if score >= 85:
        return 'A+'
    if score >= 78:
        return 'A'
    if score >= 70:
        return 'B'
    if score >= 62:
        return 'C'
    if score >= 50:
        return 'D'
    return 'F'


def _orb_base_score(c: Candidate) -> float:
    s = 0.0
    s += min(30.0, (c.today_dollar_vol or 0.0) / 25_000_000.0 * 30.0)
    s += min(30.0, (c.rvol or 0.0) / 8.0 * 30.0)
    if c.above_vwap is True:
