function computeSharesForRisk(s, riskDollars){
  const rps = Number(s?.risk_per_share);
  if (!Number.isFinite(rps) || rps<=0) return null;
  const rd = Number(riskDollars);
  if (!Number.isFinite(rd) || rd<=0) return null;
  const sh = Math.floor(rd / rps);
  return (sh>0)?sh:null;
}
function buildTicketText(s, riskDollars){
  const sym = String(s?.symbol||"").toUpperCase();
  const best = String(s?.best_side||"").toLowerCase();
  const entry = Number(s?.entry);
  const stop = Number(s?.stop_loss);
  const t2 = Number(s?.target_2r);
  const t3 = Number(s?.target_3r);
  const rps = Number(s?.risk_per_share);
  const sh = computeSharesForRisk(s, riskDollars);
  const lines = [];
  lines.push(`SYMBOL: ${sym}`);
  lines.push(`Side: ${best || "—"}`);
  if (Number.isFinite(entry)) lines.push(`Entry: ${entry.toFixed(4)}`);
  if (Number.isFinite(stop)) lines.push(`Stop: ${stop.toFixed(4)}`);
  if (Number.isFinite(t2)) lines.push(`Target 2R: ${t2.toFixed(4)}`);
  if (Number.isFinite(t3)) lines.push(`Target 3R: ${t3.toFixed(4)}`);
  if (Number.isFinite(rps)) lines.push(`Risk/share: ${rps.toFixed(4)}`);

