const orderSaveBtn = ev.target.closest('.analysisOrderSaveBtn');
if (orderSaveBtn) {
  const sym     = orderSaveBtn.dataset.sym;
  const side    = orderSaveBtn.dataset.side || 'long';
  const entry   = parseFloat(orderSaveBtn.dataset.entry);
  const stop    = parseFloat(orderSaveBtn.dataset.stop);
  const target  = parseFloat(orderSaveBtn.dataset.target);
  const ml      = orderSaveBtn.dataset.ml !== '' ? parseFloat(orderSaveBtn.dataset.ml) : null;
  const pmLast  = orderSaveBtn.dataset.pm_last !== '' ? parseFloat(orderSaveBtn.dataset.pm_last) : null;
  const pmMove  = orderSaveBtn.dataset.pm_move !== '' ? parseFloat(orderSaveBtn.dataset.pm_move) : null;
  const catalyst = orderSaveBtn.dataset.catalyst || '';
  const riskDollars = parseFloat(document.getElementById('gapRiskDollars')?.value || '50');
  const riskPerSh = Math.abs(entry - stop);
  const shares = riskPerSh > 0 ? Math.floor(riskDollars / riskPerSh) : 0;
  const dir = side === 'long' ? 1 : -1;
  try {
    const orders = JSON.parse(localStorage.getItem('gap_saved_orders') || '{}');
    orders[sym] = { sym, side, entry, stop, target, ml, pmLast, pmMove, catalyst, shares,
      r1: parseFloat((entry + dir * riskPerSh).toFixed(2)),
      r2: parseFloat((entry + dir * 2 * riskPerSh).toFixed(2)),
      r3: parseFloat((entry + dir * 3 * riskPerSh).toFixed(2)),
      savedAt: new Date().toLocaleTimeString() };
    localStorage.setItem('gap_saved_orders', JSON.stringify(orders));
    renderSavedGapOrders();
    orderSaveBtn.textContent = '✓ Saved';
    orderSaveBtn.style.background = 'rgba(251,191,36,0.3)';
  } catch(e) {
    orderSaveBtn.textContent = '✗';
  }
  setTimeout(() => {
    orderSaveBtn.textContent = '📋 Save';
    orderSaveBtn.style.background = 'rgba(251,191,36,0.15)';
  }, 1800);
  return;
}

// ── Know the Trade ────────────────────────────────────────────────
const kttBtn = ev.target.closest('.knowTradeBtn');
if (kttBtn) {
  const sym  = kttBtn.dataset.sym;
  const modal = document.getElementById('knowTradeModal');
  const body  = document.getElementById('knowTradeBody');
  const title = document.getElementById('knowTradeTitle');
  if (!modal || !body || !title) return;
  title.textContent = sym;
  modal.style.display = 'block';

  function renderKttResult(d) {
      if (!d.ok) { body.innerHTML = `<div style="color:#f87171;">Error: ${d.error}</div>`; return; }

if (d.target_hit) {
  body.innerHTML = `
    <div style="padding:20px; background:rgba(100,116,139,0.1); border:1px solid rgba(100,116,139,0.3); border-radius:10px; text-align:center;">
      <div style="font-size:40px; font-weight:900; color:#64748b; margin-bottom:8px;">✓</div>
      <div style="font-size:16px; font-weight:700; color:#94a3b8;">${esc(sym)} — Target Already Hit</div>
      <div style="font-size:13px; color:#64748b; margin-top:8px;">Live price $${fmtN(d.live_price)} has reached or exceeded the target.<br>This setup is <b style="color:#f87171;">expired</b> — do not enter a new position.</div>
    </div>`;
  return;
}

const gc = d.grade_color || '#94a3b8';
const bk = d.breakdown || {};
const sz = d.sizing || {};

// Header grade badge
const gradeHtml = `
  <div style="display:flex; align-items:center; gap:16px; padding:14px 16px; background:${gc}18; border:1px solid ${gc}44; border-radius:10px; margin-bottom:16px;">
    <div style="font-size:52px; font-weight:900; color:${gc}; line-height:1;">${esc(d.grade)}</div>
    <div>
      <div style="font-size:16px; font-weight:700; color:${gc};">${esc(sym)} — Setup Score ${d.score}/100</div>
      <div style="font-size:13px; color:#e2e8f0; margin-top:4px;">${esc(d.grade_advice)}</div>
    </div>
  </div>`;

// Score breakdown table
const bkRows = Object.entries(bk).map(([k, v]) => {
  const displayVal = v.pts ?? 0;
  const sign = displayVal >= 0 ? '+' : '';
  const col = displayVal >= 10 ? '#4ade80'
            : displayVal >= 5  ? '#fbbf24'
            : displayVal >= 0  ? '#94a3b8'
            : '#f87171';
  return `<tr>
    <td style="padding:4px 8px; color:#94a3b8; font-size:12px;">${esc(v.component)}</td>
    <td style="padding:4px 8px; font-size:12px;">${esc(v.label || v.tier || '')}</td>
    <td style="padding:4px 8px; font-weight:700; font-size:13px; color:${col}; text-align:right;">${sign}${displayVal}</td>
  </tr>`;
}).join('');

const breakdownHtml = `
  <div style="margin-bottom:14px;">
    <div style="font-size:11px; font-weight:700; color:#94a3b8; text-transform:uppercase; letter-spacing:.06em; margin-bottom:6px;">Score Breakdown</div>
    <table style="width:100%; border-collapse:collapse;">
      <tbody>${bkRows}</tbody>
      <tfoot><tr style="border-top:1px solid rgba(255,255,255,0.1);">
        <td colspan="2" style="padding:5px 8px; font-weight:700;">Total</td>
        <td style="padding:5px 8px; font-weight:700; font-size:14px; color:${gc}; text-align:right;">${d.score}/100</td>
      </tr></tfoot>
    </table>
  </div>`;

// The setup levels
const risk = (d.entry && d.stop) ? Math.abs(d.entry - d.stop).toFixed(3) : '—';
const levelsHtml = (d.entry || d.stop) ? `
  <div style="margin-bottom:14px; display:grid; grid-template-columns:repeat(4,1fr); gap:8px;">
    ${[['Entry','#fbbf24',d.entry],['Stop','#f87171',d.stop],['Target','#4ade80',d.target],['1R Risk','#94a3b8',risk]].map(([lbl,col,val])=>`
      <div style="padding:8px; background:rgba(255,255,255,0.04); border-radius:8px; text-align:center;">
        <div style="font-size:10px; color:#94a3b8; text-transform:uppercase;">${lbl}</div>
        <div style="font-size:15px; font-weight:700; color:${col};">${typeof val==='number'?'$'+fmtN(val):val??'—'}</div>
      </div>`).join('')}
  </div>` : '';

// Position sizing
const szHtml = (sz.tiers && sz.tiers.length) ? `
  <div style="margin-bottom:14px;">
    <div style="font-size:11px; font-weight:700; color:#94a3b8; text-transform:uppercase; letter-spacing:.06em; margin-bottom:6px;">Position Sizing (Grade ${esc(d.grade)} → ${Math.round((sz.tiers[0].graded_shares/Math.max(sz.tiers[0].full_shares,1))*100)}% of full size)</div>
    <div style="display:grid; grid-template-columns:repeat(3,1fr); gap:8px;">
      ${sz.tiers.map(t=>`
        <div style="padding:8px; background:rgba(255,255,255,0.04); border-radius:8px; text-align:center;">
          <div style="font-size:10px; color:#94a3b8;">${esc(t.label)}</div>
          <div style="font-size:18px; font-weight:700; color:${gc};">${t.graded_shares} <span style="font-size:11px;">shs</span></div>
          <div style="font-size:10px; color:#94a3b8;">full: ${t.full_shares} shs</div>
        </div>`).join('')}
    </div>
  </div>` : '';

// Live data row
const floatStr = d.float_shares ? fmtK(d.float_shares)+' shares' : '—';
const turnStr  = d.float_turnover_pct != null ? d.float_turnover_pct.toFixed(1)+'% of float' : '';
const liveHtml = `

def _position_sizing(entry: float | None, natural_stop: float | None,
                     grade_mult: float, stop_cap: float | None = None) -> dict:
    if not entry or not natural_stop or entry <= 0 or abs(entry - natural_stop) < 0.01:
        return {"tiers": [], "note": "Entry/stop needed for sizing"}
    natural_risk = abs(entry - natural_stop)
    cap_risk     = abs(entry - stop_cap) if stop_cap else natural_risk
    effective_risk = min(natural_risk, cap_risk)
    is_capped = stop_cap is not None and cap_risk < natural_risk
    tiers = []
