  const eodHiLo = (row.prev_high != null && row.prev_low != null)
    ? `<span style="color:#22c55e;">${row.prev_high.toFixed(2)}</span> / <span style="color:#ef4444;">${row.prev_low.toFixed(2)}</span>`
    : '—';

  const pmHiLo = (row.pm_high != null && row.pm_low != null)
    ? `<span style="color:#22c55e;">${row.pm_high.toFixed(2)}</span> / <span style="color:#ef4444;">${row.pm_low.toFixed(2)}</span>`
    : '—';

  const vsEntry = row.move_from_entry != null
    ? `<span style="color:${row.move_from_entry >= 0 ? '#22c55e' : '#94a3b8'};">${row.move_from_entry >= 0 ? '+' : ''}${row.move_from_entry.toFixed(2)}%</span>`
    : '—';

  const fmtLevel = (v, col) => v != null ? `<b style="color:${col};">$${Number(v).toFixed(2)}</b>` : '<span style="color:#555;">—</span>';

