    ? '<span style="background:#a855f722; color:#a855f7; border:1px solid #a855f744; font-size:9px; font-weight:700; padding:1px 5px; border-radius:4px; margin-left:3px;">↕</span>'
    : '';

  // News sniper conflict: sniper fired opposite direction to this row's side
  const sniperDir = (window._sniperSides || {})[row.symbol];
  const sniperConflict = sniperDir && sniperDir !== dispSide;
  const conflictBadge = sniperConflict
    ? `<span style="background:rgba(239,68,68,0.15); color:#ef4444; border:1px solid rgba(239,68,68,0.4); font-size:9px; font-weight:700; padding:1px 5px; border-radius:4px; margin-left:3px;" title="News Sniper fired ${sniperDir.toUpperCase()} — conflicts with this ${dispSide.toUpperCase()} setup. Verify before trading.">⚠ NEWS ${sniperDir.toUpperCase()}</span>`
    : '';

  html += `<tr style="border-bottom:1px solid rgba(255,255,255,0.04); background:${sniperConflict ? 'rgba(239,68,68,0.05)' : ss.bg}; border-left:3px solid ${sniperConflict ? '#ef4444' : ss.color}40;">
    <td style="padding:6px 8px; font-weight:700; color:#f1f5f9; position:sticky; left:0; z-index:2; background:#111827;">${row.symbol}</td>
    <td style="text-align:center; color:${sideColor}; font-weight:700; white-space:nowrap; position:sticky; left:62px; z-index:2; background:#111827;">${sideLabel}${reversedBadge}${conflictBadge}</td>
    <td style="text-align:right; color:#94a3b8;">${row.prev_close != null ? '$'+row.prev_close.toFixed(2) : '—'}</td>
    <td style="text-align:right;">${fmtPct(row.eod_move_pct)}</td>
    <td style="text-align:right; font-size:11px;">${eodHiLo}</td>
    <td style="text-align:center; padding:4px 6px;">${closeBar(row.eod_close_vs_rng)}</td>
