    <td style="text-align:right;">${fmtPct(row.pm_move_pct)}</td>
    <td style="text-align:right; font-size:11px;">${pmHiLo}</td>
    <td style="text-align:right; color:#94a3b8;">${fmtVol(row.pm_vol)}</td>
