    <td style="text-align:center; padding:4px 6px; font-size:11px;" title="Reg SHO SSR active — short selling restricted to uptick only">${row.ssr_active?'<span style="color:#ef4444;font-weight:700;background:rgba(239,68,68,0.12);padding:1px 6px;border-radius:4px;">SSR</span>':'<span style="color:#555;">—</span>'}</td>
    <td style="text-align:center; padding:4px 6px; font-size:11px;" title="LULD bands from SIP feed">${(()=>{const lu=(_luldMap[row.symbol]||{}).limit_up;const ld=(_luldMap[row.symbol]||{}).limit_down;if(!lu&&!ld)return'<span style="color:#555;">—</span>';const pm=row.pm_last;const nearUp=pm&&lu&&((lu-pm)/pm*100)<3;const col=nearUp?'#f59e0b':'#94a3b8';return`<span style="color:${col};font-size:10px;">&#8593;$${lu?lu.toFixed(2):'?'}&nbsp;&#8595;$${ld?ld.toFixed(2):'?'}</span>`;})()}</td>
    <td style="text-align:center; padding:4px 6px; font-size:11px;" title="${row.gap_fill_n?'Based on '+row.gap_fill_n+' prior gaps':''}">${(()=>{const r=row.gap_fill_rate;if(r==null)return'<span style="color:#555;">—</span>';const p=Math.round(r*100);const c=p<=30?'#4ade80':p<=55?'#fbbf24':'#f87171';const tip=p<=30?'follows through':p<=55?'mixed':' fades';return`<span style="color:${c};font-weight:700;" title="${tip}">${p}%</span>`;})()}</td>
    ${row.status==='stopped_out'&&row.rebuilt_entry!=null?`
    <td style="text-align:right; padding:4px 8px;" title="Rebuilt from last 30-min PM bars">${fmtLevel(row.rebuilt_entry,'#f59e0b')} <span style="font-size:9px;color:#f59e0b;opacity:0.7;">🔄</span></td>
