const STATUS_STYLE = {
  intact:      { color: '#22c55e',  bg: '#22c55e18', label: '✓ Intact'        },
  near_entry:  { color: '#f59e0b',  bg: '#f59e0b18', label: '⚡ Near entry'    },
  triggered:   { color: '#818cf8',  bg: '#818cf818', label: '▶ Triggered'     },
  stopped_out: { color: '#ef4444',  bg: '#ef444418', label: '✗ Invalidated'   },
  target_hit:  { color: '#64748b',  bg: 'rgba(100,116,139,0.08)', label: '✓ Target hit — expired' },
  no_pm_data:  { color: '#94a3b8',  bg: 'transparent', label: '— No PM data'  },
  no_levels:   { color: '#94a3b8',  bg: 'transparent', label: '— No levels'   },
};

// ── Midday Filter ─────────────────────────────────────────────────────────
// A row is "still viable" at midday if it passes ALL of:
//   1. Not stopped_out / target_hit / no_levels / no_pm_data
//   2. RVOL >= 1.5x  OR  catalyst < 2h (fresh news overrides volume)
//   3. If triggered: price hasn't fallen back below entry (move_from_entry >= -0.25)
//   4. Gap fill rate < 0.70 for longs, > 0.30 for shorts (history not against the trade)
let _middayFilterOn = false;

function _isViableAtMidday(tr) {
  const status = tr.dataset.mdfStatus || '';
  const rvol   = parseFloat(tr.dataset.mdfRvol)    || 0;
  const catAge = parseFloat(tr.dataset.mdfCatAge);
  const vse    = parseFloat(tr.dataset.mdfVse);      // move_from_entry %
  const fill   = parseFloat(tr.dataset.mdfFill);
  const side   = tr.dataset.mdfSide || 'long';

  if (['stopped_out','target_hit','no_levels','no_pm_data'].includes(status)) return false;
  const freshNews = !isNaN(catAge) && catAge < 2;
  if (rvol < 1.5 && !freshNews) return false;
  if (status === 'triggered' && !isNaN(vse) && vse < -0.25) return false;
  if (!isNaN(fill)) {
    if (side === 'long'  && fill >= 0.70) return false;
    if (side === 'short' && fill <= 0.30) return false;
  }
  return true;
}

function _applyMiddayFilter() {
  const rows = analysisBody ? analysisBody.querySelectorAll('tr[data-mdf-row]') : [];
  if (!rows.length) return;
  let viableCount = 0;
  rows.forEach(tr => {
    const viable = _isViableAtMidday(tr);
    if (_middayFilterOn) {
      tr.style.display = viable ? '' : 'none';
    } else {
      tr.style.display = '';
    }
    if (viable) {
      viableCount++;
      tr.dataset.mdfViable = '1';
      tr.style.outline = _middayFilterOn ? '1px solid rgba(251,191,36,0.5)' : '';
    } else {
      delete tr.dataset.mdfViable;
      tr.style.outline = '';
    }
  });

  const mdfBtn = document.getElementById('middayFilterBtn');
  if (mdfBtn) {
    if (_middayFilterOn) {
      mdfBtn.textContent = `⏰ Midday Filter ON (${viableCount} viable)`;
      mdfBtn.style.background = 'rgba(251,191,36,0.28)';
      mdfBtn.style.color = '#fde68a';
      mdfBtn.style.borderColor = 'rgba(251,191,36,0.7)';
    } else {
      mdfBtn.textContent = viableCount > 0
        ? `⏰ Midday Filter (${viableCount} viable)`
        : '⏰ Midday Filter (0 viable)';
      mdfBtn.style.background = 'rgba(251,191,36,0.12)';
      mdfBtn.style.color = '#fbbf24';
      mdfBtn.style.borderColor = 'rgba(251,191,36,0.3)';
    }
  }
}

const mdfBtnEl = document.getElementById('middayFilterBtn');
if (mdfBtnEl) {
  mdfBtnEl.addEventListener('click', () => {
    _middayFilterOn = !_middayFilterOn;
    _applyMiddayFilter();
  });
}

