import json

def extract_session(path, label):
    edits = []
    msgs = []
    with open(path) as f:
        for line in f:
            try:
                msg = json.loads(line)
                # Handle nested message structure
                for key in ['message', 'msg']:
                    if key in msg:
                        msg = msg[key]
                        break
                role = msg.get('role','')
                content = msg.get('content','')
                if isinstance(content, list):
                    for block in content:
                        if not isinstance(block, dict): continue
                        if block.get('type') == 'tool_use' and block.get('name') in ('Edit','Write','Bash'):
                            inp = block.get('input',{})
                            fp = inp.get('file_path','') or inp.get('command','')[:80]
                            edits.append(fp)
                elif isinstance(content, str) and role == 'assistant' and len(content) > 100:
                    msgs.append(content[:300])
            except: pass
    print(f'\\n=== {label} ===')
    print(f'  Tool calls: {len(edits)}')
    for e in edits[:30]:
        print(f'    {e}')
    if msgs:
        print(f'  First assistant msg: {msgs[0][:200]}')

